import numpy as np
from scipy.stats import norm

class GreeksCalculator:
    def __init__(self, S: float, K: float, r: float, sigma: float, T: float, is_call: bool):
        self.S, self.K, self.r, self.sigma, self.T = S, K, r, sigma, T
        self.is_call = is_call

    def d1(self) -> float:
        return (np.log(self.S/self.K) + (self.r + 0.5*self.sigma**2)*self.T) / (self.sigma*np.sqrt(self.T))

    def d2(self) -> float:
        return self.d1() - self.sigma*np.sqrt(self.T)

    def delta(self) -> float:
        if self.is_call:
            return norm.cdf(self.d1())
        return norm.cdf(self.d1()) - 1

    def gamma(self) -> float:
        return norm.pdf(self.d1()) / (self.S * self.sigma * np.sqrt(self.T))

    def vega(self) -> float:
        return self.S * np.sqrt(self.T) * norm.pdf(self.d1()) * 0.01

    def theta(self) -> float:
        d1, d2 = self.d1(), self.d2()
        term1 = -self.S * norm.pdf(d1) * self.sigma / (2*np.sqrt(self.T))
        if self.is_call:
            term2 = -self.r * self.K * np.exp(-self.r*self.T) * norm.cdf(d2)
        else:
            term2 = self.r * self.K * np.exp(-self.r*self.T) * norm.cdf(-d2)
        return (term1 + term2) / 365

    def rho(self) -> float:
        d2 = self.d2()
        if self.is_call:
            return self.K * self.T * np.exp(-self.r*self.T) * norm.cdf(d2) * 0.01
        return -self.K * self.T * np.exp(-self.r*self.T) * norm.cdf(-d2) * 0.01

    def vanna(self) -> float:
        d1, d2 = self.d1(), self.d2()
        return -norm.pdf(d1) * d2 / self.sigma

    def volga(self) -> float:
        d1, d2 = self.d1(), self.d2()
        return self.vega() * d1 * d2 / self.sigma

