import numpy as np
from typing import List, Dict

class PortfolioGreeks:
    def __init__(self):
        self.positions: List[Dict] = []

    def add_option(self, delta: float, gamma: float, vega: float, theta: float, quantity: int):
        self.positions.append({'delta': delta, 'gamma': gamma, 'vega': vega, 'theta': theta, 'qty': quantity})

    def add_stock(self, shares: int):
        self.positions.append({'delta': 1, 'gamma': 0, 'vega': 0, 'theta': 0, 'qty': shares})

    def portfolio_greeks(self) -> Dict[str, float]:
        totals = {'delta': 0, 'gamma': 0, 'vega': 0, 'theta': 0}
        for pos in self.positions:
            totals['delta'] += pos['delta'] * pos['qty']
            totals['gamma'] += pos['gamma'] * pos['qty']
            totals['vega'] += pos['vega'] * pos['qty']
            totals['theta'] += pos['theta'] * pos['qty']
        return totals

    def dollar_delta(self, spot: float) -> float:
        return self.portfolio_greeks()['delta'] * spot

