import numpy as np
from typing import Callable, Dict

class NumericalGreeks:
    def __init__(self, pricer: Callable, base_params: Dict):
        self.pricer = pricer
        self.base = base_params

    def delta(self, bump_pct: float = 0.01) -> float:
        h = self.base['spot'] * bump_pct
        up = {**self.base, 'spot': self.base['spot'] + h}
        down = {**self.base, 'spot': self.base['spot'] - h}
        return (self.pricer(up) - self.pricer(down)) / (2*h)

    def gamma(self, bump_pct: float = 0.01) -> float:
        h = self.base['spot'] * bump_pct
        up = {**self.base, 'spot': self.base['spot'] + h}
        down = {**self.base, 'spot': self.base['spot'] - h}
        return (self.pricer(up) - 2*self.pricer(self.base) + self.pricer(down)) / (h**2)

    def vega(self, bump: float = 0.01) -> float:
        up = {**self.base, 'vol': self.base['vol'] + bump}
        down = {**self.base, 'vol': self.base['vol'] - bump}
        return (self.pricer(up) - self.pricer(down)) / (2*bump) * 0.01

import numpy as np
from typing import List, Dict

class ScenarioAnalyzer:
    def __init__(self, delta: float, gamma: float, vega: float):
        self.delta = delta
        self.gamma = gamma
        self.vega = vega

    def pnl_estimate(self, spot_change: float, vol_change: float) -> Dict:
        delta_pnl = self.delta * spot_change
        gamma_pnl = 0.5 * self.gamma * spot_change**2
        vega_pnl = self.vega * (vol_change / 0.01)
        return {
            'delta_pnl': delta_pnl,
            'gamma_pnl': gamma_pnl,
            'vega_pnl': vega_pnl,
            'total_pnl': delta_pnl + gamma_pnl + vega_pnl
        }

    def scenario_matrix(self, spot_changes: List[float], vol_changes: List[float]) -> np.ndarray:
        result = np.zeros((len(spot_changes), len(vol_changes)))
        for i, ds in enumerate(spot_changes):
            for j, dv in enumerate(vol_changes):
                result[i,j] = self.pnl_estimate(ds, dv)['total_pnl']
        return result

