import numpy as np
from typing import Dict, List

class RiskReporter:
    def __init__(self, portfolio_value: float, greeks: Dict[str, float]):
        self.value = portfolio_value
        self.greeks = greeks

    def summary(self, spot: float) -> Dict:
        return {
            'portfolio_value': self.value,
            'greeks': self.greeks,
            'dollar_delta': self.greeks['delta'] * spot,
            'dollar_gamma': 0.5 * self.greeks['gamma'] * spot**2 * 0.01**2,
            '1pct_spot_pnl': self.greeks['delta'] * spot * 0.01 + 0.5 * self.greeks['gamma'] * (spot*0.01)**2,
            '1pct_vol_pnl': self.greeks['vega'],
            'daily_theta': self.greeks['theta']
        }

    def var_1pct_move(self) -> Dict:
        d = self.greeks['delta']
        g = self.greeks['gamma']
        return {
            'up_1pct': d * 0.01 + 0.5 * g * 0.01**2,
            'down_1pct': -d * 0.01 + 0.5 * g * 0.01**2
        }

    def theta_report(self, days: int = 5) -> List[Dict]:
        theta = self.greeks['theta']
        return [{'day': i+1, 'cumulative_decay': theta * (i+1), 'remaining_value': self.value + theta*(i+1)} for i in range(days)]
